import React from "react";
import { useEffect } from "react";
import "./App.css";
import * as THREE from "three";
import { GLTFLoader } from "three/examples/jsm/loaders/GLTFLoader.js";
import Header from "./Header.js";
import { ThemeProvider } from "emotion-theming";
import theme from "./theme.js";

function App() {
  useEffect(() => {
    var scene = new THREE.Scene();
    var width = window.innerWidth;
    var height = window.innerHeight;
    const camera = new THREE.OrthographicCamera(
      width / -2,
      width / 2,
      height / 2,
      height / -2,
      0,
      1000
    );
    const cameraY = 10;
    const cameraX = 0;
    camera.position.y = 10;
    camera.position.z = 20;
    camera.zoom = 18;
    camera.updateProjectionMatrix();

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    document.body.appendChild(renderer.domElement);
    const hemiLight = new THREE.HemisphereLight(0xffffbb, 0x080820, 1);
    hemiLight.castShadow = true;
    scene.add(hemiLight);
    const dirLight = new THREE.DirectionalLight(0xffffff, 1);
    dirLight.position.set(5, 2, 8);
    dirLight.castShadow = true;
    scene.add(dirLight);
    scene.background = new THREE.Color("#141301");

    const loader = new GLTFLoader();
    let desk = null;
    loader.load("./desk.gltf", function (gltf) {
      desk = gltf.scene;
      scene.add(desk);
      desk.rotation.x = 0.35;
      desk.position.x = 1.5;
      desk.traverse((node) => {
        if (node.isMesh) {
          node.castShadow = true;
          node.receiveShadow = true;
        }
      });
    });

    const mouse = new THREE.Vector2();

    function onMouseMove(event) {
      mouse.x = (event.clientX / window.innerWidth) * 2 - 1;
      mouse.y = (event.clientY / window.innerHeight) * 2 - 1;
    }

    window.addEventListener("mousemove", onMouseMove, false);
    window.onresize = function () {
      camera.aspect = window.innerWidth / window.innerHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(window.innerWidth, window.innerHeight);
    };

    function clamp(value, min, max) {
      return Math.min(Math.max(value, min), max);
    }

    var animate = function () {
      camera.position.x = cameraX + clamp(mouse.x * -0.5, -2, 2);
      camera.position.y = cameraY + clamp(mouse.y * 0.5, -2, 2);
      requestAnimationFrame(animate);
      if (desk) {
        desk.position.y = 0.1 * Math.sin(Date.now() / 300);
        desk.rotation.y += 0.003;
      }
      renderer.render(scene, camera);
    };
    animate();
  }, []);
  return (
    <div className="main">
      <ThemeProvider theme={theme}>
        <Header />
      </ThemeProvider>
    </div>
  );
}

export default App;
