import React from "react";
import { Box, Flex, Button, Link } from "rebass";

function Links() {
  return (
    <Flex>
      <Box width={1} alignItems="center" py={3} textAlign="center">
        <Link href={"https://www.linkedin.com/in/douglascheong/"}>
          <Button mx={2}>LinkedIn</Button>
        </Link>
        <Link href={"https://github.com/dcheong"}>
          <Button mx={2}>GitHub</Button>
        </Link>
      </Box>
    </Flex>
  );
}

export default Links;
